>>>>>>> branch 'dev_' of https://github.com/limhyojin3/SpringProjectTeam3.git SELECT r.res_no, r.user_id, m.tel, r.product_no, r.company_no, c.com_name, r.res_date, r.res_time, r.res_status, r.res_content, r.use_date, r.use_time, r.pay_date, r.pay_no, p.product_name, p.product_details, p.original_price, p.is_active, p.img_url, /* 💡 버그 척결 핵심: 존재하지 않아 에러를 내뿜던 유령 컬럼 p.pro_type 완벽 도려내기 차단 완료 */ /* 💡 연쇄 버그 방어: p.tag 역시 존재하지 않는 에러 유발선이므로, 안전하게 콤마로 묶어 전달하는 독립 서브쿼리 서랍으로 전면 교체 완료 */ ( SELECT GROUP_CONCAT(pt_all.tag SEPARATOR ',') FROM product_tag_map ptm_all INNER JOIN product_tag pt_all ON ptm_all.tag_id = pt_all.id WHERE ptm_all.product_no = p.product_no ) AS tag, p.deposit, pr.amount, pr.pay_status, pr.refund, pr.refund_date FROM reservation r LEFT JOIN product p ON p.product_no = r.product_no LEFT JOIN payment_reservation pr ON r.res_no = pr.res_no INNER JOIN company c ON c.company_no = r.company_no INNER JOIN member m ON m.user_id = r.user_id WHERE r.user_id = #{userId}
